async (params, browser) => {
  // Open StockX search
  await browser.open(`https://stockx.com/search?s=${params.query}`)

  // Wait for results
  await browser.waitForSelector('[data-testid=\'product-card\'], [class*=\'ProductCard\'], [class*=\'tile\']', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const results = []; document.querySelectorAll('[data-testid="product-card"], [class*="ProductCard"], [class*="tile"] a').forEach((el, i) => { if (i < 15) { const nameEl = el.querySelector('p, [class*="name"], h3'); const priceEl = el.querySelector('[class*="price"], [class*="amount"]'); const imgEl = el.querySelector('img'); results.push({ name: nameEl?.textContent?.trim() || '', price: priceEl?.textContent?.trim() || '', image: imgEl?.src || '', url: el.href || el.querySelector('a')?.href || '' }); } }); return { query: '' + params.query + '', result_count: results.length, results };`)

  return search_results
}
